# Integration test: deploy the example on real AWS (sandbox profile) and assert
# the resource values. terraform test destroys everything at the end of the file.
# Requires AWS credentials (AWS_PROFILE=sandbox). The random suffix makes the
# bucket name globally unique.

run "setup" {
  module {
    source = "./tests/setup"
  }
}

run "deploy_and_assert" {
  command = apply

  variables {
    bucket_name        = "bga-tftest-${run.setup.suffix}"
    environment        = "dev"
    versioning_enabled = true
    force_destroy      = true
  }

  assert {
    condition     = output.bucket_id == "bga-tftest-${run.setup.suffix}"
    error_message = "deployed bucket id must match the requested name"
  }

  assert {
    condition     = output.versioning_status == "Enabled"
    error_message = "versioning must be Enabled on the deployed bucket"
  }

  assert {
    condition     = output.encryption_enabled == false
    error_message = "CMK encryption must be off (AWS-managed key fallback) when no key is provided"
  }
}

# Parallelism: deploy the example twice in parallel without collision.
# Distinct state_key -> isolated state (1.11+); parallel = true runs them concurrently (1.12+).
# Requires AWS credentials (AWS_PROFILE=sandbox).

run "setup" {
  module {
    source = "./tests/setup"
  }
}

# Shared variables
variables {
  environment   = "dev"
  force_destroy = true
}

run "deploy_a" {
  command   = apply
  parallel  = true
  state_key = "a"
  variables {
    bucket_name = "bga-tftest-a-${run.setup.suffix}"
  }
  assert {
    condition     = output.bucket_id == "bga-tftest-a-${run.setup.suffix}"
    error_message = "bucket A name mismatch"
  }
}

run "deploy_b" {
  command   = apply
  parallel  = true
  state_key = "b"
  variables {
    bucket_name = "bga-tftest-b-${run.setup.suffix}"
  }
  assert {
    condition     = output.bucket_id == "bga-tftest-b-${run.setup.suffix}"
    error_message = "bucket B name mismatch"
  }
}
